import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/vm-arguments.BmU0TYdw.js";const s=JSON.parse(`{"title":"Corriendo tu Juego","description":"Aprende a utilizar los perfiles de lanzamiento varios para cargar y depurar tus mods en un entorno de juego en vivo.","frontmatter":{"title":"Corriendo tu Juego","description":"Aprende a utilizar los perfiles de lanzamiento varios para cargar y depurar tus mods en un entorno de juego en vivo.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"es_es/1.21.8/develop/getting-started/launching-the-game.md","filePath":"versions/1.21.8/translated/es_es/develop/getting-started/launching-the-game.md","lastUpdated":1760721669000}`);var c={name:`es_es/1.21.8/develop/getting-started/launching-the-game.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Corriendo tu Juego <a class="header-anchor" href="#h1" aria-label="Permalink to “Corriendo tu Juego”">​</a></h1><p>Fabric Loom provee una variedad de perfiles de lanzamiento para ayudarte a correr y depurar tus mods en un entorno de juego en vivo. Esta guía cubrirá los perfiles de lanzamiento varios y como usarlos para depurar y probar tus mods.</p><h2 id="perfiles-de-lanzamiento" tabindex="-1">Perfiles de Lanzamiento <a class="header-anchor" href="#perfiles-de-lanzamiento" aria-label="Permalink to “Perfiles de Lanzamiento”">​</a></h2><p>Si estás usando IntelliJ IDEA, puedes encontrar los perfiles de lanzamiento en la esquina superior derecha de la ventana. Haz clic en el menú desplegable para ver los perfiles de lanzamiento disponibles.</p><p>Debería haber un perfil para el cliente y el servidor, con la opción de correr cualquiera de los dos normalmente o en modo de depuración:</p><p><img src="/assets/develop/getting-started/launch-profiles.png" alt="Perfiles de Lanzamiento" loading="lazy"></p><h2 id="tareas-de-gradle" tabindex="-1">Tareas de Gradle <a class="header-anchor" href="#tareas-de-gradle" aria-label="Permalink to “Tareas de Gradle”">​</a></h2><p>Si estás usando la línea de comandos, puedes usar los siguientes comandos de Gradle para empezar el juego:</p><ul><li><code>./gradlew runClient</code> - Lanza el juego en modo de cliente.</li><li><code>./gradlew runServer</code> - Lanza el juego en modo de servidor.</li></ul><p>El único problema con esta opción es que no puedes depurar tu código fácilmente. Si quieres depurar tu código, deberás usar los perfiles de lanzamiento en IntelliJ IDEA o mediante la integración de Gradle de tu IDE.</p><h2 id="intercambiar-clases-en-tiempo-de-ejecucion" tabindex="-1">Intercambiar Clases en tiempo de ejecución <a class="header-anchor" href="#intercambiar-clases-en-tiempo-de-ejecucion" aria-label="Permalink to “Intercambiar Clases en tiempo de ejecución”">​</a></h2><p>Cuando corres el juego en modo de depuración, puedes intercambiar clases sin tener que reiniciar el juego. Esto es útil para probar cambios en tu código rápidamente.</p><p>Sin embargo, existen varias limitaciones:</p><ul><li>No puedes agregar o remover métodos</li><li>No puedes cambiar los parámetros de un método</li><li>No puedes agregar o remover miembros</li></ul><h2 id="intercambiar-mixins-en-tiempo-de-ejecucion" tabindex="-1">Intercambiar Mixins en tiempo de ejecución <a class="header-anchor" href="#intercambiar-mixins-en-tiempo-de-ejecucion" aria-label="Permalink to “Intercambiar Mixins en tiempo de ejecución”">​</a></h2><p>Si estás usando Mixins, puedes intercambiar tus clases de Mixin sin tener que reiniciar el juego. Esto es útil para probar cambios en tu Mixins rápidamente.</p><p>Sin embargo, deberás instalar el <em>Mixin java agent</em> para que esto funcione.</p><h3 id="_1-localiza-el-mixin-library-jar-jar-de-libreria-de-mixin" tabindex="-1">1. Localiza el <em>Mixin Library Jar</em> (Jar de Librería de Mixin) <a class="header-anchor" href="#_1-localiza-el-mixin-library-jar-jar-de-libreria-de-mixin" aria-label="Permalink to “1. Localiza el Mixin Library Jar (Jar de Librería de Mixin)”">​</a></h3><p>En IntelliJ IDEA, puedes encontrar el jar de librería de mixin en la sección de &quot;Librerías Externas&quot; en la sección de &quot;Proyecto&quot;:</p><p><img src="/assets/develop/getting-started/mixin-library.png" alt="Librería de Mixin" loading="lazy"></p><p>Deberás copiar el &quot;absolute path&quot; (dirección absoluta) del jar para el siguiente paso.</p><h3 id="_2-agrega-el-argumento-de-vm-de-javaagent" tabindex="-1">2. Agrega el argumento de VM de <code>-javaagent</code> <a class="header-anchor" href="#_2-agrega-el-argumento-de-vm-de-javaagent" aria-label="Permalink to “2. Agrega el argumento de VM de -javaagent”">​</a></h3><p>En tus perfiles de lanzamiento de &quot;Minecraft Client&quot; y/o &quot;Minecraft Server&quot;, agrega los siguientes argumentos de VM:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>-javaagent:&quot;dirección absoluta del jar de librería de mixin aquí&quot;</span></span></code></pre></div><p><img src="/assets/develop/getting-started/vm-arguments.png" alt="Captura de pantalla los Argumentos de VM" loading="lazy"></p><p>Ahora deberías poder modificar los contenidos de tus métodos mixin durante la depuración y ver los cambios en el juego sin tener que reiniciarlo.</p>`,26)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};